import { GoogleLogin } from "@react-oauth/google";

function Login() {
  return (
    <div>
      <h2>Login</h2>

      <GoogleLogin
        onSuccess={(res) => {
          console.log(res.credential); // Google ID token
          alert("Login Successful");
        }}
        onError={() => {
          alert("Login Failed");
        }}
      />
    </div>
  );
}

export default Login;
